# 示例1：时间复杂度的直观对比 —— 查找元素
# 方法A：线性查找 O(n)
def linear_search(arr, target):
    for i in range(len(arr)):      # 遍历n次
        if arr[i] == target:
            return i
    return -1

# 方法B：哈希表查找 O(1)
def hash_search(hash_set, target):
    return target in hash_set       # 平均O(1)时间

# 方法C：二分查找 O(log n)，要求数组有序
def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

# 示例2：空间复杂度的权衡 —— 斐波那契数列
# 方法A：递归（时间O(2^n)，空间O(n)栈空间）
def fib_recursive(n):
    if n <= 1:
        return n
    return fib_recursive(n-1) + fib_recursive(n-2)

# 方法B：动态规划优化（时间O(n)，空间O(n)）
def fib_dp(n):
    if n <= 1:
        return n
    dp = [0] * (n + 1)
    dp[1] = 1
    for i in range(2, n + 1):
        dp[i] = dp[i-1] + dp[i-2]
    return dp[n]

# 方法C：空间压缩（时间O(n)，空间O(1)）
def fib_optimized(n):
    if n <= 1:
        return n
    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b      # 只保留前两个状态
    return b
